     1→/**
     2→ * AI Feature Extraction Stage
     3→ *
     4→ * Stage 8a of the EmailCategorizer pipeline. Uses LangChain OpenAI integration with GPT-4o-mini
     5→ * for semantic feature extraction with JSON schema validation and batch processing support.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Calling OpenAI API with structured prompts and email content
     9→ * - Validating AI responses against JSON schema
    10→ * - Extracting semantic intent and category enhancements
    11→ * - Validating evidence grounding (quoted phrases must exist in email)
    12→ * - Providing retry logic and error handling for API failures
    13→ * - Supporting batch processing with concurrent API calls
    14→ */
    15→
    16→import { OpenAI } from 'openai';
    17→import Ajv from 'ajv';
    18→import { EmailMessage, ClassificationSession } from '../types';
    19→
    20→// Configuration interface for AI feature extraction
    21→export interface AIFeatureExtractionConfig {
    22→  openai: {
    23→    apiKey: string;
    24→    model: string;
    25→    temperature: number;
    26→    responseFormat: string;
    27→  };
    28→  prompts: {
    29→    systemPrompt: string[];
    30→    userPrompt: string[];
    31→  };
    32→  featureExtractionSchema: object;
    33→  retryPolicy: {
    34→    maxRetries: number;
    35→    backoffMs: number;
    36→  };
    37→}
    38→
    39→// Semantic intent extracted by AI
    40→export interface SemanticIntent {
    41→  primary_purpose: 'notification' | 'request' | 'update' | 'alert';
    42→  action_required: 'none' | 'view' | 'respond' | 'complete';
    43→  urgency_level: 'none' | 'low' | 'medium' | 'high';
    44→}
    45→
    46→// Evidence structure for category enhancements
    47→export interface CategoryEvidence {
    48→  quoted_phrases: string[];
    49→  keywords: string[];
    50→  reasoning: string;
    51→}
    52→
    53→// Category enhancement from AI analysis
    54→export interface CategoryEnhancement {
    55→  applies: boolean;
    56→  confidence_boost: number;
    57→  evidence: CategoryEvidence;
    58→}
    59→
    60→// Complete feature extraction result from AI
    61→export interface FeatureExtractionData {
    62→  semantic_intent: SemanticIntent;
    63→  category_enhancements: Record<string, CategoryEnhancement>;
    64→}
    65→
    66→// Evidence validation result
    67→export interface EvidenceValidation {
    68→  validPhrases: string[];
    69→  invalidPhrases: string[];
    70→  fabricationDetected: boolean;
    71→}
    72→
    73→// Complete stage result interface
    74→export interface FeatureExtractionResult {
    75→  featureExtraction: FeatureExtractionData;
    76→  validationPassed: boolean;
    77→  validationErrors: string[];
    78→  evidenceValidation: EvidenceValidation;
    79→  processingDurationMs: number;
    80→  tokenUsage: number;
    81→  apiCallCount: number;
    82→  retryCount: number;
    83→}
    84→
    85→/**
    86→ * AI Feature Extraction Stage Implementation
    87→ *
    88→ * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
    89→ * category classifications with evidence-grounded analysis.
    90→ */
    91→export async function aiFeatureExtractionStage(
    92→  email: EmailMessage,
    93→  session: ClassificationSession,
    94→  candidateCategories: Record<string, unknown>,
    95→  detectedAttributes: Record<string, unknown>,
    96→  config: AIFeatureExtractionConfig
    97→): Promise<FeatureExtractionResult> {
    98→  const startTime = Date.now();
    99→  let retryCount = 0;
   100→  let apiCallCount = 0;
   101→
   102→  // Validate inputs
   103→  validateInputs(email, session, config);
   104→
   105→  // Initialize OpenAI client
   106→  const openai = new OpenAI({
   107→    apiKey: config.openai.apiKey,
   108→  });
   109→
   110→  // Setup JSON schema validator
   111→  const ajv = new Ajv();
   112→  const validateSchema = ajv.compile(config.featureExtractionSchema);
   113→
   114→  // Retry loop for API calls
   115→  let lastError: Error | null = null;
   116→
   117→  while (retryCount < config.retryPolicy.maxRetries) {
   118→    try {
   119→      apiCallCount++;
   120→
   121→      // Prepare prompts with email content interpolation
   122→      const systemPrompt = config.prompts.systemPrompt.join('\n');
   123→      const userPrompt = interpolateUserPrompt(
   124→        config.prompts.userPrompt,
   125→        email,
   126→        candidateCategories,
   127→        detectedAttributes
   128→      );
   129→
   130→      // Call OpenAI API
   131→      const response = await openai.chat.completions.create({
   132→        model: config.openai.model,
   133→        temperature: config.openai.temperature,
   134→        response_format: { type: config.openai.responseFormat as 'json_object' }, // FIXME can we make this schema-based?
   135→        messages: [
   136→          { role: 'system', content: systemPrompt },
   137→          { role: 'user', content: userPrompt },
   138→        ],
   139→      });
   140→
   141→      // Parse and validate response
   142→      const rawContent = response.choices[0].message.content;
   143→      if (!rawContent) {
   144→        throw new Error('Empty response from OpenAI');
   145→      }
   146→
   147→      let featureExtractionData: FeatureExtractionData;
   148→      try {
   149→        featureExtractionData = JSON.parse(rawContent);
   150→      } catch {
   151→        throw new Error('Invalid JSON response from OpenAI');
   152→      }
   153→
   154→      // Validate against schema
   155→      const validationPassed = validateSchema(featureExtractionData);
   156→      const validationErrors: string[] = [];
   157→
   158→      if (!validationPassed && validateSchema.errors) {
   159→        for (const error of validateSchema.errors) {
   160→          validationErrors.push(`${error.instancePath} ${error.message}`);
   161→        }
   162→        throw new Error('Schema validation failed: ' + validationErrors.join(', '));
   163→      }
   164→
   165→      // Validate evidence grounding
   166→      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);
   167→
   168→      // Success - return result
   169→      return {
   170→        featureExtraction: featureExtractionData,
   171→        validationPassed: true,
   172→        validationErrors: [],
   173→        evidenceValidation,
   174→        processingDurationMs: Date.now() - startTime,
   175→        tokenUsage: response.usage?.total_tokens || 0,
   176→        apiCallCount,
   177→        retryCount,
   178→      };
   179→    } catch (error) {
   180→      lastError = error as Error;
   181→      retryCount++;
   182→
   183→      if (retryCount < config.retryPolicy.maxRetries) {
   184→        // Wait before retry with exponential backoff
   185→        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
   186→      }
   187→    }
   188→  }
   189→
   190→  // All retries exhausted
   191→  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
   192→}
   193→
   194→/**
   195→ * Validate input parameters
   196→ */
   197→function validateInputs(email: EmailMessage, session: ClassificationSession, config: AIFeatureExtractionConfig): void {
   198→  if (!email?.id && !('gmail_id' in email)) {
   199→    throw new Error('Invalid email input: id or gmail_id is required');
   200→  }
   201→
   202→  // Allow missing subjects but log a warning - production emails might legitimately have empty subjects
   203→  if (!email.subject) {
   204→    console.warn(`Email ${email.id} has missing subject, proceeding with empty subject for classification`);
   205→  }
   206→
   207→  if (!session?.id && !('session_id' in session)) {
   208→    throw new Error('Invalid session input: id or session_id is required');
   209→  }
   210→
   211→  if (!config) {
   212→    throw new Error('Configuration is required');
   213→  }
   214→
   215→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   216→    throw new Error('Invalid configuration: OpenAI API key is required');
   217→  }
   218→
   219→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   220→    throw new Error('Invalid configuration: system and user prompts are required');
   221→  }
   222→
   223→  if (!config.featureExtractionSchema) {
   224→    throw new Error('Invalid configuration: feature extraction schema is required');
   225→  }
   226→}
   227→
   228→/**
   229→ * Interpolate user prompt template with email content and analysis data
   230→ *
   231→ * Supports dynamic object path resolution with these placeholders:
   232→ * - {email.from} - formatted email address
   233→ * - {email.subject} - email subject
   234→ * - {email.body} - email body text
   235→ * - {candidateCategories} - JSON formatted candidate categories
   236→ * - {detectedAttributes} - JSON formatted detected attributes
   237→ */
   238→function interpolateUserPrompt(
   239→  userPromptTemplate: string[],
   240→  email: EmailMessage,
   241→  candidateCategories: Record<string, unknown>,
   242→  detectedAttributes: Record<string, unknown>
   243→): string {
   244→  const template = userPromptTemplate.join('\n');
   245→
   246→  // Create interpolation context with all available data
   247→  const context = {
   248→    email: {
   249→      from: formatEmailAddress(email.from),
   250→      subject: email.subject || '',
   251→      body: getEmailBodyText(email),
   252→    },
   253→    candidateCategories: formatObjectForTemplate(candidateCategories),
   254→    detectedAttributes: formatObjectForTemplate(detectedAttributes),
   255→  };
   256→
   257→  // Perform template interpolation using dynamic path resolution
   258→  return interpolateTemplate(template, context);
   259→}
   260→
   261→/**
   262→ * Format email address for prompt display
   263→ */
   264→function formatEmailAddress(address: unknown): string {
   265→  if (!address) return 'Unknown';
   266→
   267→  if (typeof address === 'string') return address;
   268→
   269→  if (typeof address === 'object' && address !== null) {
   270→    const addr = address as Record<string, string>;
   271→    if (addr.name && addr.email) {
   272→      return `${addr.name} <${addr.email}>`;
   273→    }
   274→    return addr.email || addr.raw || 'Unknown';
   275→  }
   276→
   277→  return 'Unknown';
   278→}
   279→
   280→/**
   281→ * Extract email body text (prefer plain text, fallback to HTML with improved stripping)
   282→ */
   283→function getEmailBodyText(email: EmailMessage): string {
   284→  if (email.bodyPlain) {
   285→    return email.bodyPlain;
   286→  }
   287→
   288→  if (email.bodyHtml) {
   289→    // Improved HTML stripping with better performance and safety
   290→    return email.bodyHtml
   291→      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
   292→      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
   293→      .replace(/<[^>]*>/g, '') // Remove HTML tags
   294→      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
   295→      .replace(/\s+/g, ' ') // Normalize whitespace
   296→      .trim();
   297→  }
   298→
   299→  return '[No body content available]';
   300→}
   301→
   302→// Template object size limits (in characters)
   303→const TEMPLATE_SIZE_LIMITS = {
   304→  PRETTY_PRINT_LIMIT: 10000, // Use pretty printing below this size
   305→  COMPACT_FORMAT_LIMIT: 15000, // Use compact format below this size
   306→  MAX_TEMPLATE_SIZE: 20000, // Truncate above this size
   307→} as const;
   308→
   309→/**
   310→ * Check if an object contains null/empty values that would benefit from compaction
   311→ * Includes depth limits to prevent excessive recursion
   312→ */
   313→function hasCompactableContent(obj: Record<string, unknown>, maxDepth = 10): boolean {
   314→  if (maxDepth <= 0) return false; // Prevent deep recursion
   315→
   316→  for (const value of Object.values(obj)) {
   317→    if (value === null || value === undefined) return true;
   318→    if (Array.isArray(value) && value.length === 0) return true;
   319→    if (typeof value === 'object' && value !== null) {
   320→      const objValue = value as Record<string, unknown>;
   321→      if (Object.keys(objValue).length === 0) return true;
   322→      if (hasCompactableContent(objValue, maxDepth - 1)) return true;
   323→    }
   324→  }
   325→  return false;
   326→}
   327→
   328→/**
   329→ * Format an object for template inclusion with progressive compaction
   330→ *
   331→ * Progressive approach:
   332→ * 1. Check if compaction would be beneficial (has nulls/empties)
   333→ * 2. If beneficial, apply compaction first
   334→ * 3. Choose format based on size: pretty -> compact -> minified -> truncated
   335→ * Optimized to minimize JSON.stringify() calls for better performance
   336→ */
   337→function formatObjectForTemplate(obj: Record<string, unknown>): string {
   338→  const startTime = Date.now();
   339→  let originalSize: number | undefined;
   340→
   341→  try {
   342→    // Step 1: Determine if we should compact (has null/empty values)
   343→    const shouldCompact = hasCompactableContent(obj);
   344→    const objectToFormat = shouldCompact ? createCompactedObject(obj) : obj;
   345→
   346→    // Step 2: Calculate compact JSON first (smallest computation)
   347→    const compactJson = JSON.stringify(objectToFormat);
   348→
   349→    // Add memory usage warning for large objects
   350→    if (compactJson.length > 100000) {
   351→      // 100KB threshold
   352→      console.warn(`Large object detected (${compactJson.length} chars). Consider processing in smaller chunks.`);
   353→    }
   354→
   355→    // Step 3: Choose format based on compact size (avoiding additional stringify calls)
   356→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.PRETTY_PRINT_LIMIT) {
   357→      // Only calculate pretty JSON if compact format would fit in pretty limit
   358→      const prettyJson = JSON.stringify(objectToFormat, null, 2);
   359→      return prettyJson;
   360→    }
   361→
   362→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.COMPACT_FORMAT_LIMIT) {
   363→      return compactJson;
   364→    }
   365→
   366→    // Step 4: Try minified version without extra spaces
   367→    const minifiedJson = compactJson.replace(/\s+/g, ' ').trim();
   368→    if (minifiedJson.length <= TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE) {
   369→      return minifiedJson;
   370→    }
   371→
   372→    // Step 5: Truncate with ellipsis and log warning
   373→    // Only calculate original size if we need it for error logging
   374→    originalSize = shouldCompact ? JSON.stringify(obj).length : compactJson.length;
   375→    const truncated = minifiedJson.substring(0, TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE - 50) + '...[truncated]';
   376→
   377→    const processingTime = Date.now() - startTime;
   378→    console.warn(
   379→      `Object too large for template after compaction. Original: ${originalSize} chars, ` +
   380→        `Compacted: ${compactJson.length} chars, Truncated to: ${truncated.length} chars, ` +
   381→        `Processing time: ${processingTime}ms`
   382→    );
   383→    return '[Object too large for template - see logs for details]';
   384→  } catch (error) {
   385→    const processingTime = Date.now() - startTime;
   386→    console.warn('Object formatting error:', {
   387→      error: error instanceof Error ? error.message : 'Unknown error',
   388→      originalSize: originalSize || 'unknown',
   389→      processingTime: `${processingTime}ms`,
   390→    });
   391→    return '[Object formatting error]';
   392→  }
   393→}
   394→
   395→/**
   396→ * Create a deeply compacted version of an object by removing nulls, empties recursively
   397→ * with protection against circular references and stack overflow
   398→ */
   399→function createCompactedObject(obj: Record<string, unknown>): Record<string, unknown> {
   400→  const seen = new WeakSet<object>();
   401→  const result = compactValue(obj, seen, 0);
   402→  return (result as Record<string, unknown>) || {};
   403→}
   404→
   405→/**
   406→ * Recursively compact a single value with circular reference detection and depth limits
   407→ */
   408→function compactValue(value: unknown, seen = new WeakSet<object>(), depth = 0): unknown {
   409→  const MAX_DEPTH = 10; // Much more conservative depth limit
   410→
   411→  if (depth > MAX_DEPTH) {
   412→    console.warn(`Object nesting too deep (>${MAX_DEPTH} levels), stopping compaction`);
   413→    return undefined; // Remove deeply nested content to prevent issues
   414→  }
   415→
   416→  if (value === null || value === undefined) {
   417→    return undefined;
   418→  }
   419→
   420→  if (Array.isArray(value)) {
   421→    if (seen.has(value)) {
   422→      return '[Circular Reference]'; // Prevent infinite loops
   423→    }
   424→    seen.add(value);
   425→
   426→    const compactedArray = value
   427→      .map((item) => compactValue(item, seen, depth + 1))
   428→      .filter((item) => item !== undefined);
   429→
   430→    seen.delete(value); // Clean up for other branches
   431→    return compactedArray.length > 0 ? compactedArray : undefined;
   432→  }
   433→
   434→  if (typeof value === 'object' && value !== null) {
   435→    if (seen.has(value)) {
   436→      return '[Circular Reference]'; // Prevent infinite loops
   437→    }
   438→    seen.add(value);
   439→
   440→    const compactedObj: Record<string, unknown> = {};
   441→    let hasValidProperties = false;
   442→
   443→    for (const [key, val] of Object.entries(value)) {
   444→      const compactedVal = compactValue(val, seen, depth + 1);
   445→      if (compactedVal !== undefined) {
   446→        compactedObj[key] = compactedVal;
   447→        hasValidProperties = true;
   448→      }
   449→    }
   450→
   451→    seen.delete(value); // Clean up for other branches
   452→    return hasValidProperties ? compactedObj : undefined;
   453→  }
   454→
   455→  return value;
   456→}
   457→
   458→/**
   459→ * Template interpolation engine with dynamic path resolution and security safeguards
   460→ *
   461→ * Supports placeholders like {object.property} and {simpleProperty}
   462→ * Prevents template injection by sanitizing paths and output values
   463→ */
   464→function interpolateTemplate(template: string, context: Record<string, unknown>): string {
   465→  return template.replace(/{([^}]+)}/g, (match, path) => {
   466→    // Sanitize path to prevent injection - only allow alphanumeric, dots, and underscores
   467→    if (!/^[a-zA-Z][a-zA-Z0-9._]*$/.test(path)) {
   468→      return match; // Reject suspicious paths
   469→    }
   470→
   471→    try {
   472→      const pathParts = path.split('.');
   473→      let value: unknown = context;
   474→
   475→      for (const part of pathParts) {
   476→        if (value && typeof value === 'object' && value !== null && part in value) {
   477→          value = (value as Record<string, unknown>)[part];
   478→        } else {
   479→          return match; // Keep original placeholder if path not found
   480→        }
   481→      }
   482→
   483→      // Type-safe string conversion with output sanitization
   484→      if (typeof value === 'string') {
   485→        // Sanitize output to prevent prompt injection by escaping template characters
   486→        return sanitizeTemplateOutput(value);
   487→      } else if (typeof value === 'number' || typeof value === 'boolean') {
   488→        return String(value);
   489→      } else if (value != null) {
   490→        return sanitizeTemplateOutput(String(value));
   491→      } else {
   492→        return match; // Keep original placeholder if null/undefined
   493→      }
   494→    } catch {
   495→      // If path resolution fails, keep original placeholder
   496→      return match;
   497→    }
   498→  });
   499→}
   500→
   501→/**
   502→ * Sanitize template output to prevent injection attacks
   503→ *
   504→ * Enhanced security with robust JSON detection and aggressive sanitization
   505→ */
   506→function sanitizeTemplateOutput(value: string): string {
   507→  // More robust JSON detection to prevent bypass attacks
   508→  const looksLikeJson = (() => {
   509→    try {
   510→      JSON.parse(value);
   511→      return true; // Valid JSON
   512→    } catch {
   513→      // Fallback heuristic for JSON-like strings
   514→      const trimmed = value.trim();
   515→      return (
   516→        trimmed.startsWith('{') &&
   517→        trimmed.endsWith('}') &&
   518→        trimmed.includes(':') &&
   519→        trimmed.includes('"') &&
   520→        !trimmed.includes('{{') // Avoid false positives with nested braces
   521→      );
   522→    }
   523→  })();
   524→
   525→  if (looksLikeJson) {
   526→    // For JSON, only normalize whitespace but preserve structure
   527→    return value
   528→      .replace(/[\n\r\t]/g, ' ')
   529→      .replace(/\s+/g, ' ')
   530→      .trim();
   531→  } else {
   532→    // For plain text, aggressively sanitize all template-like patterns
   533→    return value
   534→      .replace(/\{+([^}]*)\}+/g, '[$1]') // Handle multiple braces: {{evil}} -> [evil]
   535→      .replace(/[\n\r\t]/g, ' ') // Normalize all whitespace characters
   536→      .replace(/\s+/g, ' ') // Collapse multiple spaces
   537→      .trim();
   538→  }
   539→}
   540→
   541→/**
   542→ * Validate that quoted phrases in evidence actually exist in the email content
   543→ */
   544→function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
   545→  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
   546→  const validPhrases: string[] = [];
   547→  const invalidPhrases: string[] = [];
   548→
   549→  // Check all quoted phrases in category enhancements
   550→  for (const [, enhancement] of Object.entries(featureExtraction.category_enhancements || {})) {
   551→    if (enhancement.evidence?.quoted_phrases) {
   552→      for (const phrase of enhancement.evidence.quoted_phrases) {
   553→        const normalizedPhrase = phrase.toLowerCase().trim();
   554→        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
   555→          validPhrases.push(phrase);
   556→        } else if (normalizedPhrase) {
   557→          invalidPhrases.push(phrase);
   558→        }
   559→      }
   560→    }
   561→  }
   562→
   563→  return {
   564→    validPhrases,
   565→    invalidPhrases,
   566→    fabricationDetected: invalidPhrases.length > 0,
   567→  };
   568→}
