/**
 * AI Feature Extraction Stage
 *
 * Stage 8a of the EmailCategorizer pipeline. Uses LangChain OpenAI integration with GPT-4o-mini
 * for semantic feature extraction with JSON schema validation and batch processing support.
 *
 * This stage is responsible for:
 * - Calling OpenAI API with structured prompts and email content
 * - Validating AI responses against JSON schema
 * - Extracting semantic intent and category enhancements
 * - Validating evidence grounding (quoted phrases must exist in email)
 * - Providing retry logic and error handling for API failures
 * - Supporting batch processing with concurrent API calls
 */

import { OpenAI } from 'openai';
import Ajv from 'ajv';
import { EmailMessage, ClassificationSession } from '../types';

// Configuration interface for AI feature extraction
export interface AIFeatureExtractionConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: 'json_schema' | 'json_object'; // Support both for backward compatibility
  };
  prompts: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  featureExtractionSchema: {
    name?: string;
    description?: string;
    schema: Record<string, unknown>;
    strict?: boolean;
  };
  retryPolicy: {
    maxRetries: number;
    backoffMs: number;
  };
}

// Semantic intent extracted by AI
export interface SemanticIntent {
  primary_purpose: 'notification' | 'request' | 'update' | 'alert';
  action_required: 'none' | 'view' | 'respond' | 'complete';
  urgency_level: 'none' | 'low' | 'medium' | 'high';
}

// Evidence structure for category enhancements
export interface CategoryEvidence {
  quoted_phrases: string[];
  keywords: string[];
  reasoning: string;
}

// Category enhancement from AI analysis
export interface CategoryEnhancement {
  applies: boolean;
  confidence_boost: number;
  evidence: CategoryEvidence;
}

// Complete feature extraction result from AI
export interface FeatureExtractionData {
  semantic_intent: SemanticIntent;
  category_enhancements: Record<string, CategoryEnhancement>;
}

// Evidence validation result
export interface EvidenceValidation {
  validPhrases: string[];
  invalidPhrases: string[];
  fabricationDetected: boolean;
}

// Complete stage result interface
export interface FeatureExtractionResult {
  featureExtraction: FeatureExtractionData;
  validationPassed: boolean;
  validationErrors: string[];
  evidenceValidation: EvidenceValidation;
  processingDurationMs: number;
  tokenUsage: number;
  apiCallCount: number;
  retryCount: number;
}

/**
 * AI Feature Extraction Stage Implementation
 *
 * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
 * category classifications with evidence-grounded analysis.
 */
export async function aiFeatureExtractionStage(
  email: EmailMessage,
  session: ClassificationSession,
  candidateCategories: Record<string, unknown>,
  detectedAttributes: Record<string, unknown>,
  config: AIFeatureExtractionConfig
): Promise<FeatureExtractionResult> {
  const startTime = Date.now();
  let retryCount = 0;
  let apiCallCount = 0;

  // Validate inputs
  validateInputs(email, session, config);

  // Initialize OpenAI client
  const openai = new OpenAI({
    apiKey: config.openai.apiKey,
  });

  // Setup JSON schema validator
  const ajv = new Ajv();
  const validateSchema = ajv.compile(config.featureExtractionSchema);

  // Retry loop for API calls
  let lastError: Error | null = null;

  while (retryCount < config.retryPolicy.maxRetries) {
    try {
      apiCallCount++;

      // Prepare prompts with email content interpolation
      const systemPrompt = config.prompts.systemPrompt.join('\n');
      const userPrompt = interpolateUserPrompt(
        config.prompts.userPrompt,
        email,
        candidateCategories,
        detectedAttributes
      );

      // Prepare response format based on configuration
      const responseFormat =
        config.openai.responseFormat === 'json_schema'
          ? {
            type: 'json_schema' as const,
            json_schema: {
              name: config.featureExtractionSchema.name || 'feature_extraction',
              description:
                  config.featureExtractionSchema.description ||
                  'Extract semantic features and category enhancements from email content',
              schema: config.featureExtractionSchema.schema,
              strict: config.featureExtractionSchema.strict ?? true,
            },
          }
          : { type: 'json_object' as const }; // Backward compatibility

      // Call OpenAI API with structured outputs
      const response = await openai.chat.completions.create({
        model: config.openai.model,
        temperature: config.openai.temperature,
        response_format: responseFormat,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      });

      // Parse and validate response
      const rawContent = response.choices[0].message.content;
      if (!rawContent) {
        throw new Error('Empty response from OpenAI');
      }

      let featureExtractionData: FeatureExtractionData;
      try {
        featureExtractionData = JSON.parse(rawContent);
      } catch {
        throw new Error('Invalid JSON response from OpenAI');
      }

      // Validate against schema
      const validationPassed = validateSchema(featureExtractionData);
      const validationErrors: string[] = [];

      if (!validationPassed && validateSchema.errors) {
        for (const error of validateSchema.errors) {
          validationErrors.push(`${error.instancePath} ${error.message}`);
        }
        throw new Error('Schema validation failed: ' + validationErrors.join(', '));
      }

      // Validate evidence grounding
      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);

      // Success - return result
      return {
        featureExtraction: featureExtractionData,
        validationPassed: true,
        validationErrors: [],
        evidenceValidation,
        processingDurationMs: Date.now() - startTime,
        tokenUsage: response.usage?.total_tokens || 0,
        apiCallCount,
        retryCount,
      };
    } catch (error) {
      lastError = error as Error;
      retryCount++;

      if (retryCount < config.retryPolicy.maxRetries) {
        // Wait before retry with exponential backoff
        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
      }
    }
  }

  // All retries exhausted
  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
}

/**
 * Validate input parameters
 */
function validateInputs(email: EmailMessage, session: ClassificationSession, config: AIFeatureExtractionConfig): void {
  if (!email?.id && !('gmail_id' in email)) {
    throw new Error('Invalid email input: id or gmail_id is required');
  }

  // Allow missing subjects but log a warning - production emails might legitimately have empty subjects
  if (!email.subject) {
    console.warn(`Email ${email.id} has missing subject, proceeding with empty subject for classification`);
  }

  if (!session?.id && !('session_id' in session)) {
    throw new Error('Invalid session input: id or session_id is required');
  }

  if (!config) {
    throw new Error('Configuration is required');
  }

  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
    throw new Error('Invalid configuration: OpenAI API key is required');
  }

  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
    throw new Error('Invalid configuration: system and user prompts are required');
  }

  if (!config.featureExtractionSchema) {
    throw new Error('Invalid configuration: feature extraction schema is required');
  }
}

/**
 * Interpolate user prompt template with email content and analysis data
 *
 * Supports dynamic object path resolution with these placeholders:
 * - {email.from} - formatted email address
 * - {email.subject} - email subject
 * - {email.body} - email body text
 * - {candidateCategories} - JSON formatted candidate categories
 * - {detectedAttributes} - JSON formatted detected attributes
 */
function interpolateUserPrompt(
  userPromptTemplate: string[],
  email: EmailMessage,
  candidateCategories: Record<string, unknown>,
  detectedAttributes: Record<string, unknown>
): string {
  const template = userPromptTemplate.join('\n');

  // Create interpolation context with all available data
  const context = {
    email: {
      from: formatEmailAddress(email.from),
      subject: email.subject || '',
      body: getEmailBodyText(email),
    },
    candidateCategories: formatObjectForTemplate(candidateCategories),
    detectedAttributes: formatObjectForTemplate(detectedAttributes),
  };

  // Perform template interpolation using dynamic path resolution
  return interpolateTemplate(template, context);
}

/**
 * Format email address for prompt display
 */
function formatEmailAddress(address: unknown): string {
  if (!address) return 'Unknown';

  if (typeof address === 'string') return address;

  if (typeof address === 'object' && address !== null) {
    const addr = address as Record<string, string>;
    if (addr.name && addr.email) {
      return `${addr.name} <${addr.email}>`;
    }
    return addr.email || addr.raw || 'Unknown';
  }

  return 'Unknown';
}

/**
 * Extract email body text (prefer plain text, fallback to HTML with improved stripping)
 */
function getEmailBodyText(email: EmailMessage): string {
  if (email.bodyPlain) {
    return email.bodyPlain;
  }

  if (email.bodyHtml) {
    // Improved HTML stripping with better performance and safety
    return email.bodyHtml
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
      .replace(/<[^>]*>/g, '') // Remove HTML tags
      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
      .replace(/\s+/g, ' ') // Normalize whitespace
      .trim();
  }

  return '[No body content available]';
}

// Template object size limits (in characters)
const TEMPLATE_SIZE_LIMITS = {
  PRETTY_PRINT_LIMIT: 10000, // Use pretty printing below this size
  COMPACT_FORMAT_LIMIT: 15000, // Use compact format below this size
  MAX_TEMPLATE_SIZE: 20000, // Truncate above this size
} as const;

/**
 * Check if an object contains null/empty values that would benefit from compaction
 * Includes depth limits to prevent excessive recursion
 */
function hasCompactableContent(obj: Record<string, unknown>, maxDepth = 10): boolean {
  if (maxDepth <= 0) return false; // Prevent deep recursion

  for (const value of Object.values(obj)) {
    if (value === null || value === undefined) return true;
    if (Array.isArray(value) && value.length === 0) return true;
    if (typeof value === 'object' && value !== null) {
      const objValue = value as Record<string, unknown>;
      if (Object.keys(objValue).length === 0) return true;
      if (hasCompactableContent(objValue, maxDepth - 1)) return true;
    }
  }
  return false;
}

/**
 * Format an object for template inclusion with progressive compaction
 *
 * Progressive approach:
 * 1. Check if compaction would be beneficial (has nulls/empties)
 * 2. If beneficial, apply compaction first
 * 3. Choose format based on size: pretty -> compact -> minified -> truncated
 * Optimized to minimize JSON.stringify() calls for better performance
 */
function formatObjectForTemplate(obj: Record<string, unknown>): string {
  const startTime = Date.now();
  let originalSize: number | undefined;

  try {
    // Step 1: Determine if we should compact (has null/empty values)
    const shouldCompact = hasCompactableContent(obj);
    const objectToFormat = shouldCompact ? createCompactedObject(obj) : obj;

    // Step 2: Calculate compact JSON first (smallest computation)
    const compactJson = JSON.stringify(objectToFormat);

    // Add memory usage warning for large objects
    if (compactJson.length > 100000) {
      // 100KB threshold
      console.warn(`Large object detected (${compactJson.length} chars). Consider processing in smaller chunks.`);
    }

    // Step 3: Choose format based on compact size (avoiding additional stringify calls)
    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.PRETTY_PRINT_LIMIT) {
      // Only calculate pretty JSON if compact format would fit in pretty limit
      const prettyJson = JSON.stringify(objectToFormat, null, 2);
      return prettyJson;
    }

    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.COMPACT_FORMAT_LIMIT) {
      return compactJson;
    }

    // Step 4: Try minified version without extra spaces
    const minifiedJson = compactJson.replace(/\s+/g, ' ').trim();
    if (minifiedJson.length <= TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE) {
      return minifiedJson;
    }

    // Step 5: Truncate with ellipsis and log warning
    // Only calculate original size if we need it for error logging
    originalSize = shouldCompact ? JSON.stringify(obj).length : compactJson.length;
    const truncated = minifiedJson.substring(0, TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE - 50) + '...[truncated]';

    const processingTime = Date.now() - startTime;
    console.warn(
      `Object too large for template after compaction. Original: ${originalSize} chars, ` +
        `Compacted: ${compactJson.length} chars, Truncated to: ${truncated.length} chars, ` +
        `Processing time: ${processingTime}ms`
    );
    return '[Object too large for template - see logs for details]';
  } catch (error) {
    const processingTime = Date.now() - startTime;
    console.warn('Object formatting error:', {
      error: error instanceof Error ? error.message : 'Unknown error',
      originalSize: originalSize || 'unknown',
      processingTime: `${processingTime}ms`,
    });
    return '[Object formatting error]';
  }
}

/**
 * Create a deeply compacted version of an object by removing nulls, empties recursively
 * with protection against circular references and stack overflow
 */
function createCompactedObject(obj: Record<string, unknown>): Record<string, unknown> {
  const seen = new WeakSet<object>();
  const result = compactValue(obj, seen, 0);
  return (result as Record<string, unknown>) || {};
}

/**
 * Recursively compact a single value with circular reference detection and depth limits
 */
function compactValue(value: unknown, seen = new WeakSet<object>(), depth = 0): unknown {
  const MAX_DEPTH = 10; // Much more conservative depth limit

  if (depth > MAX_DEPTH) {
    console.warn(`Object nesting too deep (>${MAX_DEPTH} levels), stopping compaction`);
    return undefined; // Remove deeply nested content to prevent issues
  }

  if (value === null || value === undefined) {
    return undefined;
  }

  if (Array.isArray(value)) {
    if (seen.has(value)) {
      return '[Circular Reference]'; // Prevent infinite loops
    }
    seen.add(value);

    const compactedArray = value
      .map((item) => compactValue(item, seen, depth + 1))
      .filter((item) => item !== undefined);

    seen.delete(value); // Clean up for other branches
    return compactedArray.length > 0 ? compactedArray : undefined;
  }

  if (typeof value === 'object' && value !== null) {
    if (seen.has(value)) {
      return '[Circular Reference]'; // Prevent infinite loops
    }
    seen.add(value);

    const compactedObj: Record<string, unknown> = {};
    let hasValidProperties = false;

    for (const [key, val] of Object.entries(value)) {
      const compactedVal = compactValue(val, seen, depth + 1);
      if (compactedVal !== undefined) {
        compactedObj[key] = compactedVal;
        hasValidProperties = true;
      }
    }

    seen.delete(value); // Clean up for other branches
    return hasValidProperties ? compactedObj : undefined;
  }

  return value;
}

/**
 * Template interpolation engine with dynamic path resolution and security safeguards
 *
 * Supports placeholders like {object.property} and {simpleProperty}
 * Prevents template injection by sanitizing paths and output values
 */
function interpolateTemplate(template: string, context: Record<string, unknown>): string {
  return template.replace(/{([^}]+)}/g, (match, path) => {
    // Sanitize path to prevent injection - only allow alphanumeric, dots, and underscores
    if (!/^[a-zA-Z][a-zA-Z0-9._]*$/.test(path)) {
      return match; // Reject suspicious paths
    }

    try {
      const pathParts = path.split('.');
      let value: unknown = context;

      for (const part of pathParts) {
        if (value && typeof value === 'object' && value !== null && part in value) {
          value = (value as Record<string, unknown>)[part];
        } else {
          return match; // Keep original placeholder if path not found
        }
      }

      // Type-safe string conversion with output sanitization
      if (typeof value === 'string') {
        // Sanitize output to prevent prompt injection by escaping template characters
        return sanitizeTemplateOutput(value);
      } else if (typeof value === 'number' || typeof value === 'boolean') {
        return String(value);
      } else if (value != null) {
        return sanitizeTemplateOutput(String(value));
      } else {
        return match; // Keep original placeholder if null/undefined
      }
    } catch {
      // If path resolution fails, keep original placeholder
      return match;
    }
  });
}

/**
 * Sanitize template output to prevent injection attacks
 *
 * Enhanced security with robust JSON detection and aggressive sanitization
 */
function sanitizeTemplateOutput(value: string): string {
  // More robust JSON detection to prevent bypass attacks
  const looksLikeJson = (() => {
    try {
      JSON.parse(value);
      return true; // Valid JSON
    } catch {
      // Fallback heuristic for JSON-like strings
      const trimmed = value.trim();
      return (
        trimmed.startsWith('{') &&
        trimmed.endsWith('}') &&
        trimmed.includes(':') &&
        trimmed.includes('"') &&
        !trimmed.includes('{{') // Avoid false positives with nested braces
      );
    }
  })();

  if (looksLikeJson) {
    // For JSON, only normalize whitespace but preserve structure
    return value
      .replace(/[\n\r\t]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  } else {
    // For plain text, aggressively sanitize all template-like patterns
    return value
      .replace(/\{+([^}]*)\}+/g, '[$1]') // Handle multiple braces: {{evil}} -> [evil]
      .replace(/[\n\r\t]/g, ' ') // Normalize all whitespace characters
      .replace(/\s+/g, ' ') // Collapse multiple spaces
      .trim();
  }
}

/**
 * Validate that quoted phrases in evidence actually exist in the email content
 */
function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
  const validPhrases: string[] = [];
  const invalidPhrases: string[] = [];

  // Check all quoted phrases in category enhancements
  for (const [, enhancement] of Object.entries(featureExtraction.category_enhancements || {})) {
    if (enhancement.evidence?.quoted_phrases) {
      for (const phrase of enhancement.evidence.quoted_phrases) {
        const normalizedPhrase = phrase.toLowerCase().trim();
        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
          validPhrases.push(phrase);
        } else if (normalizedPhrase) {
          invalidPhrases.push(phrase);
        }
      }
    }
  }

  return {
    validPhrases,
    invalidPhrases,
    fabricationDetected: invalidPhrases.length > 0,
  };
}

