          score: null, // Should cause entire object to be removed
          confidence: null,
          decision: null,
          notes: null,
          tags: [],
          metadata: {},
        },
        empty_category: {}, // Should be removed entirely
        another_empty: { field1: null, field2: undefined, field3: [] }, // Should be removed entirely
        valid_data: {
          keep: 'this',
          nested: {
            also_keep: 'this',
            remove_null: null, // Should be removed
          },
        },
        // Add moderate padding to trigger compaction but not truncation
        padding: Array.from({ length: 500 }, (_, i) => `medium_padding_${i}`).join(' '),
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
