  const mockSemanticIntent = {
    primary_purpose: 'notification' as const,
    action_required: 'view' as const,
    urgency_level: 'medium' as const,
  };

  describe('Security Enhancements and Robustness', () => {
    it('should prevent stack overflow with deeply nested objects', async () => {
      // Create a deeply nested object that would cause stack overflow
      const deepObj: Record<string, unknown> = {};
      let current = deepObj;
      for (let i = 0; i < 100; i++) {
        // 100 levels deep
        current.nested = { level: i, nullValue: null };
        current = current.nested as Record<string, unknown>;
      }

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
