        valid_json: '{"key": "value", "nested": {"prop": "data"}}',
        regular_field: 'normal text with {template} chars',
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: mockSemanticIntent,
                category_enhancements: {},
              }),
            },
          },
        ],
        usage: { total_tokens: 50 },
      });

      await aiFeatureExtractionStage(mockEmail, mockSession, candidatesWithJson, mockDetectedAttributes, mockConfig);

      const calledArgs = mockCreate.mock.calls[0][0];
      const userMessage = calledArgs.messages[1].content;

      // JSON should be preserved (even if escaped), templates in plain text should be sanitized
      expect(userMessage).toContain('"key"'); // JSON key preserved
      expect(userMessage).toContain('"value"'); // JSON value preserved
      expect(userMessage).toContain('[template]'); // Template sanitized
    });

    it('should limit compaction depth to prevent excessive recursion', async () => {
      // Create an object with excessive nesting
      const veryDeepObj: Record<string, unknown> = { data: 'root' };
      let current = veryDeepObj;
      for (let i = 0; i < 20; i++) {
        // 20 levels deep
        current.deep = { level: i, nullValue: null, empty: [] };
        current = current.deep as Record<string, unknown>;
      }

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: mockSemanticIntent,
                category_enhancements: {},
              }),
            },
          },
        ],
        usage: { total_tokens: 50 },
      });

      // Should complete without hanging or excessive processing time
      const startTime = Date.now();
      const result = await aiFeatureExtractionStage(mockEmail, mockSession, veryDeepObj, {}, mockConfig);
      const endTime = Date.now();

      expect(result.featureExtraction).toBeDefined();
      expect(endTime - startTime).toBeLessThan(5000); // Should complete within 5 seconds
    });
  });
});

